// Extract all text field values from Tally submission
const payload = $input.first().json;
const fields = payload?.data?.fields ?? [];

const rawText = fields
  .map(f => {
    if (typeof f.value === 'string') return f.value.trim();
    if (Array.isArray(f.value)) return f.value.join(', ');
    return '';
  })
  .filter(Boolean)
  .join('\n\n');

const submissionId = payload?.data?.submissionId ?? 'unknown';
const formId = payload?.data?.formId ?? 'unknown';

return [{
  json: {
    raw_text: rawText,
    submission_id: submissionId,
    form_id: formId,
    char_count: rawText.length,
    received_at: new Date().toISOString()
  }
}];

// Heuristic classifier — routes to appropriate refraction prompt
const text = $input.first().json.raw_text.toLowerCase();

const PROBLEM_SIGNALS = ['problem', 'issue', 'bug', 'broken', 'fails', 'blocked', 'stuck', 'cant', "can't", 'struggling'];
const DECISION_SIGNALS = ['decide', 'decision', 'choose', 'choice', 'option', 'should i', 'or should', 'trade-off', 'vs', 'versus'];
const IDEA_SIGNALS = ['idea', 'concept', 'what if', 'imagine', 'hypothesis', 'explore', 'experiment'];

const score = (signals) => signals.filter(s => text.includes(s)).length;

const scores = {
  problem: score(PROBLEM_SIGNALS),
  decision: score(DECISION_SIGNALS),
  idea: score(IDEA_SIGNALS)
};

const intent = Object.entries(scores).sort((a, b) => b[1] - a[1])[0][0];

return [{
  json: {
    ...$input.first().json,
    intent,
    intent_scores: scores
  }
}];

const claudeResponse = $input.first().json;
const content = claudeResponse?.content?.[0]?.text ?? '{}';

let refraction;
try {
  refraction = JSON.parse(content);
} catch (e) {
  // Fallback: extract JSON from text if wrapped in prose
  const match = content.match(/\{[\s\S]*\}/);
  refraction = match ? JSON.parse(match[0]) : { strategy: content, design: '', copy: '', code: '' };
}

const signalId = $('Insert Raw Signal').item.json.id;

return [{
  json: {
    signal_id: signalId,
    strategy: refraction.strategy ?? '',
    design: refraction.design ?? '',
    copy: refraction.copy ?? '',
    code: refraction.code ?? '',
    full_output: claudeResponse,
    raw_text: $('Classify Intent').item.json.raw_text
  }
}];
